begin

    process(pixel_row, pixel_col)
        variable px : integer;
        variable py : integer;
        variable sx : integer;
        variable sy : integer;
        variable color_idx : std_logic_vector(3 downto 0);
    begin
        px := to_integer(unsigned(pixel_col));
        py := to_integer(unsigned(pixel_row));

        red <= "0000";
        green <= "0000";
        blue <= "0000";
        visible <= '0';

        if (px >= FRYER_X and px < FRYER_X + FRYER_W and
            py >= FRYER_Y and py < FRYER_Y + FRYER_H) then

            sx := px - FRYER_X;
            sy := py - FRYER_Y;

            color_idx := FRYER_SPRITE(sy)(sx);

            if color_idx /= "0000" then
                visible <= '1';
            end if;

            case color_idx is
                when "0000" => 
                red <= "0000"; green <= "0000"; blue <= "0000"; -- transparent
                
                when "0001" => 
                red <= "0000"; green <= "0000"; blue <= "0000"; -- black
                
                -- brown (potato)  ~ (210,160,70)
                when "1000" => 
                red   <= "1100";
                green <= "1001";
                blue  <= "0100";
                
                -- dark brown (knife holder / patty) ~ (110,60,30)
                when "0011" => 
                red <= "0110"; green <= "0011"; blue <= "0001";
                
                -- yellow (cheese)
                when "0100" => 
                red <= "1111"; green <= "1111"; blue <= "0000";
                
                -- white
                when "0101" => 
                red <= "1111"; green <= "1111"; blue <= "1111";
                
                -- darker grey/shadow
                when "0110" => 
                red   <= "0101";
                green <= "0101";
                blue  <= "0101";
                
                -- medium grey
                when "0111" => 
                red <= "0111"; green <= "0111"; blue <= "0111";
                
                when others => red <= "0000"; green <= "0000"; blue <= "0000";
            end case;
        end if;
    end process;

end Behavioral;